const item = $input.first() || {};
const binary = item.binary || {};
const errors = [];

if (!binary.daily_file) {
  errors.push('Planilha DiÃ¡ria nÃ£o enviada (campo daily_file).');
}
if (!binary.historical_file) {
  errors.push('Dados histÃ³ricos nÃ£o enviados (campo historical_file).');
}

const crypto = require('crypto');
const requestId = crypto.randomUUID
  ? crypto.randomUUID()
  : `req_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const rawRef = String(item.json?.reference_date || item.json?.referenceDate || '').trim();
const isISODate = /^\d{4}-\d{2}-\d{2}$/.test(rawRef);
const referenceDateUsed = isISODate ? rawRef : new Date().toISOString().slice(0, 10);

if (errors.length > 0) {
  return [{
    json: {
      valid: false,
      requestId,
      errorCode: 'VALIDATION_ERROR',
      error: 'Falha na validaÃ§Ã£o do upload.',
      details: { errors },
    },
  }];
}

let historicalSheets = [];
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'historical_file');
  const jsonString = buf.toString('utf-8');
  historicalSheets = JSON.parse(jsonString);
  if (!Array.isArray(historicalSheets)) historicalSheets = [];
} catch (e) {
  errors.push('Falha ao ler JSON histÃ³rico: ' + (e.message || String(e)));
  historicalSheets = [];
}

if (historicalSheets.length === 0) {
  errors.push('Dados histÃ³ricos vazios ou com formato invÃ¡lido apÃ³s leitura.');
}

if (errors.length > 0) {
  return [{
    json: {
      valid: false,
      requestId,
      errorCode: 'VALIDATION_ERROR',
      error: 'Falha na validaÃ§Ã£o do upload.',
      details: { errors },
    },
  }];
}

const historyFilename = item.json?.historical_filename || `historico-${historicalSheets.length}-fontes`;

return [{
  json: {
    kind: 'context',
    valid: true,
    requestId,
    referenceDateUsed,
    dailyFilename: binary.daily_file?.fileName || 'daily.xlsx',
    historyFilename,
    historical_sheets: historicalSheets,
  },
  binary: { daily_file: binary.daily_file },
}];

const inputItems = $input.all();
const warnings = [];
const blockingErrors = [];

if (inputItems.some((it) => it.json?.error)) {
  blockingErrors.push('Falha ao extrair a aba Contas. Verifique se a aba existe e está legível.');
}

const rows = inputItems
  .map((it) => (Array.isArray(it.json?.row) ? it.json.row : null))
  .filter((r) => Array.isArray(r));

if (rows.length === 0) {
  blockingErrors.push('Aba Contas sem linhas utilizáveis.');
  return [{ json: { kind: 'contas', contas: [], warnings, blockingErrors } }];
}

const t = (v) => (v == null ? '' : String(v).trim());
const tu = (v) => t(v).toUpperCase();
const tl = (v) => t(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

const toNumber = (v) => {
  if (v == null || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? Math.round(v * 100) / 100 : null;
  let s = String(v).trim();
  s = s.replace(/\s+/g, '');
  if (s.includes(',') && s.includes('.')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }
  const n = Number(s);
  return Number.isFinite(n) ? Math.round(n * 100) / 100 : null;
};

const toDate = (v) => {
  if (v == null || v === '') return null;
  if (typeof v === 'number' && Number.isFinite(v)) {
    const wholeDays = Math.floor(v);
    const excelEpoch = Date.UTC(1899, 11, 30);
    const d = new Date(excelEpoch + wholeDays * 86400000);
    if (!Number.isNaN(d.getTime())) return d.toISOString().slice(0, 10);
  }
  if (Object.prototype.toString.call(v) === '[object Date]' && !Number.isNaN(v.getTime())) {
    return v.toISOString().slice(0, 10);
  }
  const s = String(v).trim();
  if (/^\d+(\.\d+)?$/.test(s)) {
    const asNum = Number(s);
    if (Number.isFinite(asNum) && asNum > 20000 && asNum < 90000) {
      const wholeDays = Math.floor(asNum);
      const excelEpoch = Date.UTC(1899, 11, 30);
      const d = new Date(excelEpoch + wholeDays * 86400000);
      if (!Number.isNaN(d.getTime())) return d.toISOString().slice(0, 10);
    }
  }
  const dmy = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (dmy) {
    const dd = dmy[1].padStart(2, '0');
    const mm = dmy[2].padStart(2, '0');
    return dmy[3] + '-' + mm + '-' + dd;
  }

  const isoLike = s.match(/^(\d{4})[-/](\d{1,2})[-/](\d{1,2})(?:[T\s].*)?$/);
  if (isoLike) {
    const yyyy = isoLike[1];
    const mm = isoLike[2].padStart(2, '0');
    const dd = isoLike[3].padStart(2, '0');
    const d = new Date(yyyy + '-' + mm + '-' + dd + 'T00:00:00Z');
    if (!Number.isNaN(d.getTime())) return yyyy + '-' + mm + '-' + dd;
  }

  return null;
};

const fieldKeywords = {
  venc: ['venc', 'vencimento'],
  fav: ['favorec', 'fornecedor', 'cliente ou fornecedor', 'cliente'],
  dep: ['depart', 'setor'],
  cat: ['categ'],
  val: ['valor'],
  parcela: ['parcel'],
  obs: ['obs', 'hist', 'descri'],
};

const subtotalPrefixes = /^(TOTAL|SALDO|DESPESA|DESPESAS|TRANSFERENCIA|TRANSFERÊNCIA|APLICA)/;

const normalizeEntityCode = (headerText) => {
  const normalized = tl(headerText);
  if (normalized.includes('prn matriz')) return 'prn_matriz';
  if (normalized.includes('cambori')) return 'prn_camboriu';
  if (normalized.includes('palhoca')) return 'prn_palhoca';
  return null;
};

const companyRowIndex = rows.findIndex((row) => row.some((cell) => tu(cell).includes('DESPESAS')));
if (companyRowIndex < 0) {
  blockingErrors.push('Cabeçalho de blocos de despesas não encontrado na aba Contas.');
  return [{ json: { kind: 'contas', contas: [], warnings, blockingErrors } }];
}

const companyRow = rows[companyRowIndex] || [];
const blockStarts = [];
for (let c = 0; c < companyRow.length; c++) {
  const text = tu(companyRow[c]);
  if (text.includes('DESPESAS')) {
    blockStarts.push(c);
  }
}

if (blockStarts.length === 0) {
  blockingErrors.push('Nenhum bloco de despesas encontrado na aba Contas.');
  return [{ json: { kind: 'contas', contas: [], warnings, blockingErrors } }];
}

const headerRowIndex = companyRowIndex + 1 < rows.length ? companyRowIndex + 1 : companyRowIndex;
const headerRow = rows[headerRowIndex] || [];

const blocks = blockStarts.map((start, index) => {
  const nextStart = index + 1 < blockStarts.length ? blockStarts[index + 1] : headerRow.length;
  const end = Math.max(start + 1, nextStart);
  const headerCells = headerRow.slice(start, end).map(tu);
  const idx = {
    venc: 0,
    fav: 1,
    dep: 2,
    cat: 3,
    val: 4,
    parcela: 5,
    obs: 6,
  };

  for (let i = 0; i < headerCells.length; i++) {
    const h = tl(headerCells[i]);
    if (!h) continue;
    if (fieldKeywords.venc.some((kw) => h.includes(kw))) idx.venc = i;
    if (fieldKeywords.fav.some((kw) => h.includes(kw))) idx.fav = i;
    if (fieldKeywords.dep.some((kw) => h.includes(kw))) idx.dep = i;
    if (fieldKeywords.cat.some((kw) => h.includes(kw))) idx.cat = i;
    if (fieldKeywords.val.some((kw) => h.includes(kw))) idx.val = i;
    if (fieldKeywords.parcela.some((kw) => h.includes(kw))) idx.parcela = i;
    if (fieldKeywords.obs.some((kw) => h.includes(kw))) idx.obs = i;
  }

  return {
    start,
    end,
    headerText: t(companyRow[start]),
    entity: normalizeEntityCode(companyRow[start]),
    idx,
  };
});

const contas = [];
const dataStart = headerRowIndex + 1;

for (let rowIndex = dataStart; rowIndex < rows.length; rowIndex++) {
  const r = rows[rowIndex] || [];

  for (const block of blocks) {
    const cells = r.slice(block.start, block.end);
    if (!cells.length || cells.every((cell) => t(cell) === '')) continue;

    const favorecido = t(cells[block.idx.fav]);
    const categoria = t(cells[block.idx.cat]);
    const valor = toNumber(cells[block.idx.val]);
    const favorecidoU = favorecido.toUpperCase();

    if (!favorecido && !categoria && (valor == null || valor === 0)) continue;
    if (!favorecido) continue;
    if (subtotalPrefixes.test(favorecidoU)) continue;
    if (favorecidoU === 'N/D') continue;

    if (valor == null) {
      warnings.push('Linha ' + (rowIndex + 1) + ' ignorada no bloco ' + (block.headerText || 'despesas') + ': valor inválido.');
      continue;
    }

    contas.push({
      entity: block.entity,
      entityLabel: block.headerText || null,
      vencimento: toDate(cells[block.idx.venc]),
      favorecido: favorecido || 'N/D',
      departamento: t(cells[block.idx.dep]) || null,
      categoria: categoria || 'Sem categoria',
      valor,
      parcela: t(cells[block.idx.parcela]) || null,
      observacao: t(cells[block.idx.obs]) || null,
      contaCorrente: null,
    });
  }
}

if (contas.length === 0) {
  warnings.push('Nenhuma despesa válida encontrada em nenhum bloco da aba Contas.');
}

return [{ json: { kind: 'contas', contas, warnings, blockingErrors } }];

const inputItems = $input.all();
const warnings = [];
const blockingErrors = [];

if (inputItems.some((it) => it.json?.error)) {
  blockingErrors.push('Falha ao extrair a aba Recebido. Verifique se a aba existe e estÃ¡ legÃ­vel.');
}

const rows = inputItems
  .map((it) => (Array.isArray(it.json?.row) ? it.json.row : null))
  .filter((r) => Array.isArray(r));

if (rows.length === 0) {
  blockingErrors.push('Aba Recebido sem linhas utilizÃ¡veis.');
  return [{ json: { kind: 'recebido', recebido: [], warnings, blockingErrors } }];
}

const t = (v) => (v == null ? '' : String(v).trim());
const tu = (v) => t(v).toUpperCase();

const toNumber = (v) => {
