/**
 * report-builder.js
 *
 * Monta o modelo final do relatÃ³rio financeiro PRN a partir dos dados
 * normalizados e dos cÃ¡lculos financeiros produzidos pelos mÃ³dulos anteriores.
 *
 * Este mÃ³dulo Ã© consumido pelo html-renderer.js para gerar a pÃ¡gina HTML final.
 *
 * Contrato de entrada:
 *   requestInfo: {
 *     requestId:            string  â€” identificador Ãºnico da requisiÃ§Ã£o (UUID)
 *     referenceDateUsed:    string  â€” data de referÃªncia no formato "YYYY-MM-DD"
 *     dailyFilename:        string  â€” nome do arquivo Excel diÃ¡rio processado
 *     historyFilename:      string  â€” nome do arquivo Excel histÃ³rico processado
 *     dailySheetsFound:    string[] â€” nomes das abas encontradas no arquivo diÃ¡rio
 *     historySheetsFound:  string[] â€” nomes das abas encontradas no arquivo histÃ³rico
 *   }
 *
 *   normalizedData: {
 *     entities: [ ... ],   â€” lista de entidades normalizadas (PRN MATRIZ, PRN LOCAÃ‡ÃƒO, etc.)
 *     expenses: [ ... ],   â€” lista de despesas normalizadas
 *     receipts: [ ... ],   â€” lista de recebidos normalizados
