 *     totalRecebido:           number â€” soma de todos os recebidos
 *     saldoBancario:           number â€” saldo total em contas bancÃ¡rias

 *     transferenciaNecessaria: number â€” valor necessÃ¡rio de transferÃªncia entre contas
 *     historyAnalysis: {       object â€” anÃ¡lise consolidada do histÃ³rico
 *       totalRecords:    number
 *       totalPago:        number
 *       totalAtrasado:    number
 *       period:           { start: string, end: string }
 *       topCategorias:    [ { categoria: string, total: number, count: number } ]
 *       topFornecedores:  [ { fornecedor: string, total: number, count: number } ]
 *       distribuicaoContas:[ { conta: string, total: number, percentual: number } ]
 *     }
 *     warnings: [ ... ]    â€” avisos produzidos durante os cÃ¡lculos financeiros
 *   }
 *
 * Retorno:
 *   Objeto completo do relatÃ³rio seguindo o schemaVersion 1.
 */

// ---------------------------------------------------------------------------
// Helpers internos
// ---------------------------------------------------------------------------

/**
 * Normaliza um valor numÃ©rico para dois decimais.
 * Se o valor for null, undefined ou NaN, retorna 0.
 *
 * @param {*} value â€” valor a normalizar
 * @returns {number} valor numÃ©rico com duas casas decimais
 */
function _normalizeNumber(value) {
  if (value === null || value === undefined || Number.isNaN(value)) {
    return 0;
  }
  const num = Number(value);
  return Number.isFinite(num) ? parseFloat(num.toFixed(2)) : 0;
}

/**
 * Mescla duas listas de warnings em uma Ãºnica lista, deduplicando por
 * combinaÃ§Ã£o de "code" + "message" (case-insensitive).
 * Cada warning deve ter a estrutura: { code, severity, message, [context] }
 *
 * @param {Array} listA â€” primeira lista de warnings
 * @param {Array} listB â€” segunda lista de warnings
 * @returns {Array} lista mesclada sem duplicatas
 */
function _mergeWarnings(listA, listB) {
  const a = Array.isArray(listA) ? listA : [];
  const b = Array.isArray(listB) ? listB : [];

  const seen = new Set();
  const merged = [];

  for (const w of [...a, ...b]) {
    if (!w || !w.message) continue;
    const key = `${String(w.code || '').toLowerCase()}|${String(w.message).toLowerCase()}`;
    if (seen.has(key)) continue;
    seen.add(key);
    merged.push({
      code: String(w.code || 'UNKNOWN'),
      severity: String(w.severity || 'info').toLowerCase(),
      message: String(w.message),
      context: w.context || undefined,
      source: w.source || undefined,
    });
  }

  return merged;
}

